=== internal/validate/validate.go ===
// Package validate renders the engine's dry-run plan as a drift report
// with stable exit codes, suitable as a CI drift guard. It is a thin
// presentation layer over engine.Plan: the engine computes the change
// set; this package shapes the output and maps drift to an exit code.
package validate

import (
	"encoding/json"
	"fmt"
	"io"

	"github.com/agent-sync/agent-sync/internal/engine"
)

// Exit codes for `agent-sync validate`. Operational errors (2+) are produced
// by the command layer, not here.
const (
	ExitNoDrift = 0
	ExitDrift   = 1
)

// SchemaVersion is the validate JSON contract version.
const SchemaVersion = 1

// targetJSON is one target's change set in the JSON contract.
type targetJSON struct {
	Target      string   `json:"target"`
	WouldCreate []string `json:"would_create"`
	WouldUpdate []string `json:"would_update"`
	WouldDelete []string `json:"would_delete"`
	OutOfBand   []string `json:"out_of_band_modified"`
	Warnings    []string `json:"warnings"`
	Error       string   `json:"error,omitempty"`
}

type documentJSON struct {
	SchemaVersion int          `json:"schema_version"`
	Workspace     string       `json:"workspace"`
	Commit        string       `json:"commit"`
	DriftDetected bool         `json:"drift_detected"`
	Targets       []targetJSON `json:"targets"`
}

// ExitCode maps a plan to its drift exit code.
func ExitCode(plan engine.PlanResult) int {
	if plan.DriftDetected {
		return ExitDrift
	}
	return ExitNoDrift
}

// RenderText writes a human-readable drift report.
func RenderText(w io.Writer, plan engine.PlanResult) error {
	if !plan.DriftDetected {
		_, err := fmt.Fprintln(w, "No drift: all targets are up to date.")
		return err
	}
	for _, t := range plan.Targets {
		if _, err := fmt.Fprintf(w, "target %s:\n", t.Target); err != nil {
			return err
		}
		if t.Error != "" {
			if _, err := fmt.Fprintf(w, "  error: %s\n", t.Error); err != nil {
				return err
			}
			continue
		}
		for _, list := range []struct {
			label string
			items []string
		}{
			{"create", t.WouldCreate},
			{"update", t.WouldUpdate},
			{"delete", t.WouldDelete},
			{"out-of-band-modified", t.OutOfBand},
			{"warning", t.Warnings},
		} {
			if err := writeList(w, list.label, list.items); err != nil {
				return err
			}
		}
	}
	return nil
}

func writeList(w io.Writer, label string, items []string) error {
	for _, it := range items {
		if _, err := fmt.Fprintf(w, "  %s: %s\n", label, it); err != nil {
			return err
		}
	}
	return nil
}

// MarshalJSON renders the plan as the stable validate JSON contract.
func MarshalJSON(plan engine.PlanResult) ([]byte, error) {
	doc := documentJSON{
		SchemaVersion: SchemaVersion,
		Workspace:     plan.WorkspacePath,
		Commit:        plan.Commit,
		DriftDetected: plan.DriftDetected,
		Targets:       make([]targetJSON, 0, len(plan.Targets)),
	}
	for _, t := range plan.Targets {
		doc.Targets = append(doc.Targets, targetJSON{
			Target:      t.Target,
			WouldCreate: nonNil(t.WouldCreate),
			WouldUpdate: nonNil(t.WouldUpdate),
			WouldDelete: nonNil(t.WouldDelete),
			OutOfBand:   nonNil(t.OutOfBand),
			Warnings:    nonNil(t.Warnings),
			Error:       t.Error,
		})
	}
	return json.MarshalIndent(doc, "", "  ")
}

func nonNil(s []string) []string {
	if s == nil {
		return []string{}
	}
	return s
}
=== conformance/echo/main.go ===
package main

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"regexp"

	"github.com/agent-sync/agent-sync/internal/ir"
	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

const (
	serverName    = "echo"
	serverVersion = "0.1"
	outputRoot    = ".echo"
)

var nodeIDPattern = regexp.MustCompile(`\A[a-z0-9][a-z0-9_-]{0,63}\z`)

type emitDocument struct {
	Nodes []emitNode `json:"nodes"`
}

type emitNode struct {
	ID   string          `json:"id"`
	Body json.RawMessage `json:"body"`
}

func main() {
	if err := run(context.Background()); err != nil {
		code := adapterkit.ExitCode(err)
		if code != 0 {
			os.Exit(code)
		}
		_, _ = fmt.Fprintln(os.Stderr, err)
		os.Exit(1)
	}
}

func run(ctx context.Context) error {
	server := adapterkit.NewServer(adapterkit.ServerOptions{Name: serverName, Version: serverVersion})
	server.OnInitialize(func(context.Context, adapterkit.InitializeParams) (adapterkit.InitializeResult, error) {
		return adapterkit.InitializeResult{
			Capabilities:    buildCapabilities(),
			DeclaredOutputs: []adapterkit.DeclaredOutput{{Path: outputRoot, Mode: adapterkit.OutputModeOwnedSubdir}},
		}, nil
	})
	server.OnEmit(func(ctx context.Context, params adapterkit.EmitParams) (adapterkit.EmitResult, error) {
		return handleEmit(ctx, params)
	})
	return server.Run(ctx)
}

func buildCapabilities() adapterkit.Capabilities {
	builder := adapterkit.NewCapabilities().WithWriteToolOwned(true)
	for _, kind := range ir.AllKinds() {
		builder.Supports(string(kind))
	}
	return builder.Build()
}

func handleEmit(_ context.Context, params adapterkit.EmitParams) (adapterkit.EmitResult, error) {
	var doc emitDocument
	if err := json.Unmarshal(params.IR, &doc); err != nil {
		return adapterkit.EmitResult{}, fmt.Errorf("echo: decode emit IR: %w", err)
	}

	ops := make([]adapterkit.OpRecord, 0, len(doc.Nodes)+1)
	if len(doc.Nodes) > 0 {
		mkdir := adapterkit.OpMkdir{Path: outputRoot, Mode: 0o755}
		if _, err := json.Marshal(mkdir); err != nil {
			return adapterkit.EmitResult{}, fmt.Errorf("echo: marshal mkdir op: %w", err)
		}
		ops = append(ops, adapterkit.OpRecord{Op: mkdir.OpKind(), Path: mkdir.OpPath()})
	}

	for _, node := range doc.Nodes {
		if !nodeIDPattern.MatchString(node.ID) {
			return adapterkit.EmitResult{}, &adapterkit.Error{
				Code:    adapterkit.CodeInvalidParams,
				Message: fmt.Sprintf("echo: invalid node id %q", node.ID),
			}
		}
		content, err := nodeContent(node.Body)
		if err != nil {
			return adapterkit.EmitResult{}, fmt.Errorf("echo: node %q body: %w", node.ID, err)
		}
		// Wire-protocol paths are forward-slash regardless of host OS; do not
		// switch to filepath.Join here. See
		// docs/solutions/best-practices/go-windows-cross-platform-pitfalls-2026-04-24.md
		// Rule 3 for the exception.
		writeOp, err := adapterkit.NewOpWriteFile(outputRoot+"/"+node.ID+".md", 0o644, content)
		if err != nil {
			return adapterkit.EmitResult{}, fmt.Errorf("echo: build write_file op for %q: %w", node.ID, err)
		}
		if _, err := json.Marshal(writeOp); err != nil {
			return adapterkit.EmitResult{}, fmt.Errorf("echo: marshal write_file op for %q: %w", node.ID, err)
		}
		ops = append(ops, adapterkit.OpRecord{Op: writeOp.OpKind(), Path: writeOp.OpPath()})
	}

	return adapterkit.EmitResult{OpsPerformed: ops}, nil
}

