func MapExit(err error) int {
	if err == nil {
		return exitOK
	}
	var ec exitCoder
	if errors.As(err, &ec) {
		code := ec.ExitCode()
		// An ExitCode() of 0 on a non-nil error is a contradiction; treat
		// it as a generic failure rather than silently reporting success.
		if code == 0 {
			return exitUsage
		}
		return code
	}
	return exitUsage
}
