awk -F: 'NR>1 {
  file=$1;
  pkg=file; sub(/\/[^/]+\.go$/,"",pkg);
  # remaining: line.col,line.col numstmt count  -> $3 has "start,end numstmt count"
  split($3, b, " "); stmts=b[2]; cnt=b[3];
  tot[pkg]+=stmts; if(cnt+0>0) cov[pkg]+=stmts;
}
