=== store append usage in tests ===
func TestStoreAppendThenFold(t *testing.T) {
	t.Parallel()
	s := newStoreInDir(t)

	e := mustEntry(t, OpTrust, urlX, shaA, "", "2026-05-01T12:00:00Z")
	if err := s.Append(e); err != nil {
		t.Fatalf("Append: %v", err)
	}

	m, err := s.Fold()
	if err != nil {
		t.Fatalf("Fold: %v", err)
	}
	st, ok := m[urlX]
	if !ok {
		t.Fatalf("expected entry for %q, got none", urlX)
	}
	if st.CurrentSHA != shaA {
		t.Errorf("CurrentSHA = %q, want %q", st.CurrentSHA, shaA)
	}
	if st.LastOp != OpTrust {
		t.Errorf("LastOp = %q, want trust", st.LastOp)
	}
	if st.Revoked {
		t.Error("Revoked = true, want false")
	}
}

=== Size/NeedsCompact/Compact bodies ===
func (s *Store) Size() (int64, error) {
	info, err := os.Stat(s.path)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return 0, nil
		}
		return 0, err
	}
	return info.Size(), nil
}

// NeedsCompact reports whether the store size exceeds CompactThresholdBytes.
func (s *Store) NeedsCompact() (bool, error) {
	n, err := s.Size()
	if err != nil {
		return false, err
	}
	return n > CompactThresholdBytes, nil
}

// --- package-level helpers ---

// marshalEntry serializes e to a single JSONL line (including trailing
// newline) suitable for a single write(2) call.
func marshalEntry(e LogEntry) ([]byte, error) {
	if e.TSRaw == "" && !e.TS.IsZero() {
		e.TSRaw = e.TS.UTC().Format(time.RFC3339)
	}
	b, err := json.Marshal(e)
	if err != nil {
		return nil, fmt.Errorf("trust: marshal entry: %w", err)
	}
	b = append(b, '\n')
	return b, nil
}

// parseLines decodes one LogEntry per non-empty line. Malformed lines are
// rejected with a line-number hint; lines with unknown ops are retained
// (foldEntries applies the ignore rule later).
func parseLines(r io.Reader, path string) ([]LogEntry, error) {
	sc := bufio.NewScanner(r)
	// 1 MiB scanner buffer — trust records are short but we allow headroom.
	sc.Buffer(make([]byte, 0, 64<<10), 1<<20)

	var out []LogEntry
	lineNo := 0
	for sc.Scan() {
		lineNo++
		line := sc.Bytes()
		if len(line) == 0 {
			continue
		}
		var e LogEntry
		if err := json.Unmarshal(line, &e); err != nil {
			return nil, fmt.Errorf("trust: parse %s line %d: %w", path, lineNo, err)
		}
		if e.TSRaw != "" {
			if t, err := time.Parse(time.RFC3339, e.TSRaw); err == nil {
				e.TS = t
			}
		}
		out = append(out, e)
	}
	if err := sc.Err(); err != nil {
		return nil, fmt.Errorf("trust: scan %s: %w", path, err)
	}
	return out, nil
}

// appendRawLine writes a raw line to path, used by tests to simulate
// forward-compat records from a newer binary.
=== IsZero body + PendingEntry fields ===
	URL    string    `json:"url"`
	NewSHA string    `json:"new_sha"`
	OldSHA string    `json:"old_sha"`
}

// IsZero reports whether the entry has any meaningful content.
func (e PendingEntry) IsZero() bool {
	return e.URL == "" && e.NewSHA == "" && e.OldSHA == "" && e.TSRaw == ""
}

// State is the fold-over-log output for one URL.
type State struct {
	CurrentSHA                string
	LastOp                    Op
	LastOpTS                  time.Time
	Revoked                   bool
	AllowNewSHAsOn            bool
	AllowNewSHAsCooldownUntil time.Time
}

// reSHA40 matches a lowercase hex commit SHA.
type PendingEntry struct {
	TS     time.Time `json:"-"`
	TSRaw  string    `json:"ts"`
	URL    string    `json:"url"`
	NewSHA string    `json:"new_sha"`
	OldSHA string    `json:"old_sha"`
}

