	cases := map[Source]string{
		SourceWorkspaceManifest: "workspace-manifest",
		SourcePATH:              "path",
		SourceBundled:           "bundled",
		Source(255):             "unknown",
	}
	for s, want := range cases {
		if got := s.String(); got != want {
			t.Errorf("Source(%d).String() = %q, want %q", s, got, want)
		}
	}
}

